import React, { useContext } from "react";
import { Link, graphql } from "gatsby";
import Layout, { LangContext } from "../components/Layout";
import SEO from "../components/SEO";
import { pickLangNodes, langSlug } from "../utils/i18n";

const CATEGORY_ORDER = [
  "world-crypto", "trend-scout", "vn-legal-watch", "product-engineer",
  "crypto-catalyst", "dataset-marketplace", "concept-monetizer",
];

const ReportsPage = ({ data }) => {
  const { lang } = useContext(LangContext);
  const nodes = pickLangNodes(data.allMarkdownRemark.nodes, lang);
  const categories = {};

  nodes.forEach((node) => {
    const cat = node.fields?.category || "uncategorized";
    if (!categories[cat]) {
      categories[cat] = {
        nodes: [],
        label: node.fields?.categoryLabel || cat,
        icon: node.fields?.categoryIcon || "📄",
      };
    }
    categories[cat].nodes.push(node);
  });

  const sorted = Object.entries(categories).sort(([a], [b]) => {
    const ai = CATEGORY_ORDER.indexOf(a);
    const bi = CATEGORY_ORDER.indexOf(b);
    return (ai === -1 ? 999 : ai) - (bi === -1 ? 999 : bi);
  });

  const title = lang === "vi" ? "📋 Tất cả Báo cáo" : "📋 All Reports";
  const subtitle = lang === "vi"
    ? `${nodes.length} báo cáo trong ${sorted.length} danh mục`
    : `${nodes.length} intelligence reports across ${sorted.length} categories`;
  const viewAll = lang === "vi" ? "Xem tất cả →" : "View all →";

  return (
    <Layout>
      <div className="page-header">
        <h1>{title}</h1>
        <p className="page-subtitle">{subtitle}</p>
      </div>

      <div className="report-categories">
        {sorted.map(([cat, { nodes: catNodes, label, icon }]) => (
          <section key={cat} className="category-section">
            <div className="category-header">
              <h2>
                <span className="cat-icon">{icon}</span> {label}
              </h2>
              <span className="badge">{catNodes.length}</span>
              <Link to={langSlug(`/reports/${cat}/`, lang)} className="view-all">{viewAll}</Link>
            </div>
            <div className="report-list">
              {catNodes.slice(0, 5).map((node) => (
                <Link key={node.id} to={langSlug(node.fields?.slug || "/", lang)} className="report-list-item">
                  <span className="report-date">{node.fields?.date || "—"}</span>
                  <span className="report-title">
                    {node.frontmatter?.title || `${label} — ${node.fields?.date || "Report"}`}
                  </span>
                </Link>
              ))}
            </div>
          </section>
        ))}
      </div>
    </Layout>
  );
};

export default ReportsPage;

export const Head = ({ location }) => {
  const lang = location?.pathname?.startsWith("/en") ? "en" : "vi";
  return (
    <SEO
      title={lang === "vi" ? "Báo cáo — Bobbie Intelligence" : "Reports — Bobbie Intelligence"}
      description={lang === "vi"
        ? "Tổng hợp tất cả báo cáo tình báo: tín hiệu crypto, phân tích xu hướng, cập nhật pháp lý."
        : "Browse all intelligence reports: crypto signals, trend analysis, legal updates, and opportunity radar."}
      path="/reports/"
      lang={lang}
    />
  );
};

export const query = graphql`
  query ReportsPage {
    allMarkdownRemark(sort: { fields: { date: DESC } }) {
      nodes {
        id
        fields {
          slug
          category
          categoryLabel
          categoryIcon
          categoryColor
          date
          inferredTitle
          lang
          baseName
        }
        frontmatter {
          title
          date
        }
        excerpt
      }
    }
  }
`;
