import React from "react";

/**
 * Given an array of markdown nodes (may contain both .en.md and .vi.md),
 * pick only the nodes matching the current language.
 * Falls back to English if the requested language variant doesn't exist.
 * Keys by slug (includes category) to avoid cross-category collisions.
 */
export function pickLangNodes(nodes, lang) {
  const bySlug = {};
  nodes.forEach((n) => {
    const slug = n.fields?.slug;
    if (!slug) return;
    if (!bySlug[slug]) bySlug[slug] = {};
    const l = n.fields?.lang || "en";
    bySlug[slug][l] = n;
  });

  // Preserve original order (from GraphQL sort) by iterating nodes, not bySlug
  const seen = new Set();
  const result = [];
  nodes.forEach((n) => {
    const slug = n.fields?.slug;
    if (!slug || seen.has(slug)) return;
    seen.add(slug);
    const group = bySlug[slug];
    if (group) result.push(group[lang] || group["en"] || group["vi"]);
  });
  return result.filter(Boolean);
}

/**
 * Build a language-prefixed link for a report slug.
 * slug is like "/reports/world-crypto/2026-05-05/"
 * Returns "/vi/reports/world-crypto/2026-05-05/" or "/en/..."
 */
export function langSlug(slug, lang) {
  return `/${lang || "vi"}${slug}`;
}
